// POST /token - Exchange authorization code for access token
app.post('/token', (req, res) => {
  const {
    grant_type,
    code,
    redirect_uri,
    client_id,
    client_secret,
    refresh_token
  } = req.body;

  // Also support client credentials via Authorization header
  let authenticatedClientId = client_id;
  let authenticatedClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const [headerClientId, headerClientSecret] = decoded.split(':');
    authenticatedClientId = headerClientId;
    authenticatedClientSecret = headerClientSecret;
  }

  if (!authenticatedClientId || !authenticatedClientSecret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication required. Provide client_id and client_secret in the body or via Basic auth header.'
    });
  }

  // Authenticate the client
  const client = authenticateClient(authenticatedClientId, authenticatedClientSecret);
  if (!client) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Invalid client credentials'
    });
  }

  if (grant_type === 'authorization_code') {
    return handleAuthorizationCodeGrant(req, res, client, code, redirect_uri);
  } else if (grant_type === 'refresh_token') {
    return handleRefreshTokenGrant(req, res, client, refresh_token);
  } else {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Supported grant types: authorization_code, refresh_token'
    });
  }
});

function handleAuthorizationCodeGrant(req, res, client, code, redirect_uri) {
  if (!code) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Authorization code is required'
    });
  }

  if (!redirect_uri) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'redirect_uri is required'
    });
  }

  const codeData = authorizationCodes.get(code);

  if (!codeData) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid or unknown authorization code'
    });
  }

  // Check if code has been used (prevent replay attacks)
  if (codeData.used) {
    // Revoke all tokens issued with this code (security measure)
    console.log(`[SECURITY] Authorization code replay detected for code: ${code.substring(0, 8)}... Revoking associated tokens.`);
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has already been used'
    });
  }

  // Check if code has expired
  if (Date.now() > codeData.expires_at) {
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has expired'
    });
  }

  // Validate client_id matches
  if (codeData.client_id !== client.client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was not issued to this client'
    });
  }

  // Validate redirect_uri matches
  if (codeData.redirect_uri !== redirect_uri) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'redirect_uri does not match the one used during authorization'
    });
  }

  // Mark code as used
  codeData.used = true;
  authorizationCodes.set(code, codeData);

  // Generate tokens
  const accessToken = generateToken();
  const newRefreshToken = generateToken();

  const tokenData = {
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600, // 1 hour
    refresh_token: newRefreshToken,
    scope: codeData.scope,
    created_at: Date.now()
  };

  // Store access token
  accessTokens.set(accessToken, {
    token: accessToken,
    client_id: client.client_id,
    username: codeData.username,
    scope: codeData.scope,
    expires_at: Date.now() + (3600 * 1000),
    created_at: Date.now()
  });

  // Store refresh token
  refreshTokens.set(newRefreshToken, {
    token: newRefreshToken,
    client_id: client.client_id,
    username: codeData.username,
    scope: codeData.scope,
    created_at: Date.now()
  });

  console.log(`[TOKEN] Access token issued for user "${codeData.username}" to client "${client.client_id}"`);

  res.json(tokenData);
}

function handleRefreshTokenGrant(req, res, client, refreshToken) {
  if (!refreshToken) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'refresh_token is required'
    });
  }

  const storedRefreshToken = refreshTokens.get(refreshToken);

  if (!storedRefreshToken) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid or unknown refresh token'
    });
  }

  if (storedRefreshToken.client_id !== client.client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token was not issued to this client'
    });
  }

  // Revoke old refresh token (rotation)
  refreshTokens.delete(refreshToken);

  // Generate new tokens
  const newAccessToken = generateToken();
  const newRefreshToken = generateToken();

  // Store new access token
  accessTokens.set(newAccessToken, {
    token: newAccessToken,
    client_id: client.client_id,
    username: storedRefreshToken.username,
    scope: storedRefreshToken.scope,
    expires_at: Date.now() + (3600 * 1000),
    created_at: Date.now()
  });

  // Store new refresh token
  refreshTokens.set(newRefreshToken, {
    token: newRefreshToken,
    client_id: client.client_id,
    username: storedRefreshToken.username,
    scope: storedRefreshToken.scope,
    created_at: Date.now()
  });

  console.log(`[TOKEN] Token refreshed for user "${storedRefreshToken.username}" to client "${client.client_id}"`);

  res.json({
    access_token: newAccessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: newRefreshToken,
    scope: storedRefreshToken.scope
  });
}

// Token introspection endpoint (RFC 7662)
app.post('/token/introspect', (req, res) => {
  const { token } = req.body;

  if (!token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'token parameter is required'
    });
  }

  const tokenData = accessTokens.get(token);

  if (!tokenData || Date.now() > tokenData.expires_at) {
    return res.json({ active: false });
  }

  const user = users.get(tokenData.username);

  res.json({
    active: true,
    scope: tokenData.scope,
    client_id: tokenData.client_id,
    username: tokenData.username,
    token_type: 'Bearer',
    exp: Math.floor(tokenData.expires_at / 1000),
    iat: Math.floor(tokenData.created_at / 1000),
    sub: tokenData.username,
    name: user ? user.name : undefined,
    email: user ? user.email : undefined
  });
});

// Token revocation endpoint (RFC 7009)
app.post('/token/revoke', (req, res) => {
  const { token, token_type_hint } = req.body;

  if (!token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'token parameter is required'
    });
  }

  // Try to revoke as access token
  if (accessTokens.has(token)) {
    accessTokens.delete(token);
    console.log(`[REVOKE] Access token revoked`);
  }

  // Try to revoke as refresh token
  if (refreshTokens.has(token)) {
    refreshTokens.delete(token);
    console.log(`[REVOKE] Refresh token revoked`);
  }

  // Always return 200 regardless (per RFC 7009)
  res.status(200).json({ message: 'Token revoked successfully' });
});

// Protected resource endpoint (for testing)
app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Bearer token required'
    });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Invalid or unknown access token'
    });
  }

  if (Date.now() > tokenData.expires_at) {
    accessTokens.delete(token);
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Access token has expired'
    });
  }

  const user = users.get(tokenData.username);
  if (!user) {
    return res.status(404).json({
      error: 'user_not_found',
      error_description: 'User associated with this token was not found'
    });
  }

  res.json({
    sub: user.username,
    name: user.name,
    email: user.email,
    scope: tokenData.scope
  });
});

// Client registration endpoint (for administrative use)
app.post('/clients', (req, res) => {
  const { client_name, redirect_uris: clientRedirectUris } = req.body;

  if (!client_name || !clientRedirectUris || !Array.isArray(clientRedirectUris) || clientRedirectUris.length === 0) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'client_name and redirect_uris (array) are required'
    });
  }

  const clientId = 'client_' + crypto.randomBytes(16).toString('hex');
  const clientSecret = crypto.randomBytes(32).toString('hex');

  const newClient = {
    client_id: clientId,
    client_secret: clientSecret,
    redirect_uris: clientRedirectUris,
    name: client_name
  };

  clients.set(clientId, newClient);

  console.log(`[CLIENT] New client registered: "${client_name}" (${clientId})`);

  res.status(201).json({
    client_id: clientId,
    client_secret: clientSecret,
    client_name: client_name,
    redirect_uris: clientRedirectUris
  });
});

