// Cleanup expired codes and tokens periodically
setInterval(() => {
  const now = Date.now();
  let cleanedCodes = 0;
  let cleanedTokens = 0;

  for (const [key, value] of authorizationCodes.entries()) {
    if (now > value.expires_at) {
      authorizationCodes.delete(key);
      cleanedCodes++;
    }
  }

  for (const [key, value] of accessTokens.entries()) {
    if (now > value.expires_at) {
      accessTokens.delete(key);
      cleanedTokens++;
    }
  }

  if (cleanedCodes > 0 || cleanedTokens > 0) {
    console.log(`[CLEANUP] Removed ${cleanedCodes} expired codes and ${cleanedTokens} expired tokens`);
  }
}, 60 * 1000); // Run every minute

